export interface ReactNativeCodegenSignature {
  name: string;
  signature: string;
  isAsync: boolean;
}

export interface BrickCodegenSignature {
  name: string;
  signature: string;
  isAsync: boolean;
}

/**
 * Converts React Native Codegen signature to Brick Codegen signature
 */
export function mapReactNativeCodegenToBrickSignature(
  rnSignature: ReactNativeCodegenSignature,
): BrickCodegenSignature {
  let signature = rnSignature.signature;

  // 1. Convert C++ struct references to id
  signature = signature.replace(/JS::NativeBrickModule::\w+\s*&/g, "id");

  // 2. Convert NSDictionary * return type to id (for complex objects)
  if (
    signature.includes("- (NSDictionary *)") &&
    isComplexObjectMethod(rnSignature.name)
  ) {
    signature = signature.replace("- (NSDictionary *)", "- (id)");
  }

  // 3. Simplify NSArray<NSString *> * to NSArray *
  signature = signature.replace(/NSArray<[^>]+>\s*\*/g, "NSArray *");

  // 4. Remove semicolon (optional)
  signature = signature.replace(/;$/, "");

  return {
    name: rnSignature.name,
    signature: signature,
    isAsync: rnSignature.isAsync,
  };
}

/**
 * Checks if method handles complex objects
 */
function isComplexObjectMethod(methodName: string): boolean {
  const complexObjectMethods = [
    "Calculator_oneDepth",
    "Calculator_twoDepth",
    "Calculator_threeDepth",
    "Calculator_processUser",
    "Calculator_processUsers",
  ];

  return complexObjectMethods.includes(methodName);
}

/**
 * Maps TypeScript type to Objective-C type (React Native Codegen compatible)
 */
export function mapTypeScriptTypeToObjC(
  tsType: string,
  isReturnType: boolean = false,
  isAsync: boolean = false,
): string {
  // Handle Promise type
  if (tsType.startsWith("Promise<") && tsType.endsWith(">")) {
    return "void"; // async functions return void
  }

  // Basic type mapping
  switch (tsType) {
    case "string":
      return "NSString *";
    case "number":
      if (isReturnType && !isAsync) {
        return "NSNumber *"; // sync function number return is NSNumber *
      }
      return "double"; // for parameters or async
    case "boolean":
      if (isReturnType && !isAsync) {
        return "NSNumber *"; // sync function boolean return is NSNumber *
      }
      return "BOOL"; // for parameters
    case "void":
      return "void";
    case "any":
      return "id";
    default:
      // Array type
      if (tsType.includes("[]")) {
        return "NSArray *";
      }
      // Object type
      if (tsType.startsWith("{") && tsType.endsWith("}")) {
        return isReturnType ? "id" : "id"; // complex objects use id
      }
      return "id";
  }
}

/**
 * Generates method signature
 */
export function generateMethodSignature(
  moduleName: string,
  methodName: string,
  parameters: Array<{ name: string; type: string }>,
  returnType: string,
  isAsync: boolean,
): string {
  const objcReturnType = mapTypeScriptTypeToObjC(returnType, true, isAsync);
  const fullMethodName = `${moduleName}_${methodName}`;

  let signature = `- (${objcReturnType})${fullMethodName}`;

  // Add parameters
  if (parameters.length > 0) {
    const paramStrings = parameters.map((param, index) => {
      const objcType = mapTypeScriptTypeToObjC(param.type, false, isAsync);
      if (index === 0) {
        return `:(${objcType})${param.name}`;
      } else {
        return `${param.name}:(${objcType})${param.name}`;
      }
    });
    signature += paramStrings.join(" ");
  }

  // Add resolve/reject for async functions
  if (isAsync) {
    signature = signature.replace(`- (${objcReturnType})`, "- (void)");
    signature +=
      " resolve:(RCTPromiseResolveBlock)resolve reject:(RCTPromiseRejectBlock)reject";
  }

  return signature;
}

/**
 * Removes private access modifiers from React Native Codegen generated header files
 */
export function removePrivateAccessModifiers(headerContent: string): string {
  // Remove private: line before NSDictionary *_v;
  return headerContent.replace(
    /(\s*)private:\s*\n(\s*)NSDictionary \*_v;/g,
    "$1$2NSDictionary *_v;",
  );
}
